  '213d59793c76e1d5e1965563b11b1f8dc21221f80a42f6952021e54182e7c7e2' => 'أنت <i>يجب أن</i> استخدموا الموقع على خادمكم المفتوح لإستعمال مدخل (أوث) الرجاء تحديد أباتشي <strong>https</strong> قبل تشكيل مدخل للوراء',
