  '55e9b94491541feab2756d35c31eb4ee60243b17f308013e3aa1c06e865b654d' => '<p><strong class="text-danger">ملاحظة</strong> -لا بد أن لديكِ أوراق اعتماد (إتش إس إيه) أو (إس إس إتش) لإحداث معايير على جهاز مستهدف</p>',
  '393435d60f7ea40cfe8a00e6ad32534cf9910fd7aaac830ecc1629a1926745bd' => '<p>الموقع هو عنوان مادي يمكن أن يكون له أجهزة مرتبطة به.<br/> <br/>يمكنك تعيينه إحداثيات (الطول) وإذا كانت هناك أجهزة مُعينة، سيظهر الموقع على خريطة شركة "إف بي أوديت"<br/> <br/></p>',
  '8d4c1bfe1c6975b8a8013ce842fa7e4fb416a86b44540cb12da65537fb18a77b' => '<p>تُعرّفُ الطلباتَ مِن قِبَلَك، المُستعمل والمُخزَّن لـ "إفتتاح" لإستخدام الأجهزة والارتباط بها.<br/> <br/></p>',
  'c0a80f7e82eafec124ba993bd204c773b6aab585b0e991b33e21632baf832b6e' => '<p>وتُخزَّن المواصفات لكي تستخدم في حقول معينة.</p>',
  '87ebabdea564b3097768c74cf9404b52ef023058f7ba68277ea9d75c3d6fdb1b' => '<p>وسيعرض موجز قائمة بالبنود، مجمّعة بالقيم المتميزة للمعزوّد بها <code>table</code> و <code>column</code> سمات<br/> <br/>عند تنفيذ موجز، ستكون النتيجة قائمة بالقيم المتميزة لذلك <code>table</code> و <code>column</code>سيكون هناك روابط على القيم التي تسمح للمستعمل برؤية أجهزة المطابقة<br/> <br/>إذا كانت سمة <code>extra_columns</code> أما عدد السكان، فإن الصفحة الناتجة ستتضمن هذه الأعمدة بالإضافة إلى أعمدة الأجهزة القياسية.<br/> <br/></p>',
  '89c8d04c52df242f30e612d01da6ea00f5d78e1575126c98890c957be128672a' => '<p>العميلان سمحا لك بمراجعة حسابات الشركات بدون اكتشاف تركيب الوكيل وسيتفقد الخادم كل يوم ويراجع نفسه لا يهم إن كانت حواسيبك مُطلية، فإن بيانات مراجعة الحسابات ستظهر في "إف بي أوديت".</p><p>عند الاختبار <strong>إذا</strong> وينبغي لوكيل أن يقوم بأعمال، ويجب أن تمر جميع الاختبارات الثلاثة (إذا تم إجراء الاختبار). <strong>ثم</strong> تتخذ الإجراءات.</p>',
  '42b1c35a5a01fef6e61e8bcd32ba9d7051de05df091ea298c1546ed82a77d648' => '<p>وتُخزَّن المجموعات في نظام &quot; مفتوح العضوية &quot; من أجل الأجهزة الشريكة من أجل تحسين تسجيل وإدارة وتقدير تكاليف الترخيص.<br/> <br/></p>',
  '491b795f44e2a7eaca1a772d619c487929fed43468f2dc3789955326be1cca09' => '<p><strong>خط الأساس</strong> - الوثيقة الشاملة التي تتضمن تعريف خط الأساس واختبارات السياسات الفردية.<br/> <br/> <strong>السياسات</strong> - الاختبارات الفردية الواردة في خط الأساس. كل اختبار هو لبند محدد ومن الأمثلة على ذلك اختبار النسخة 1-2-3 من الوثيقة SSH.<br/> <br/> <strong>التفاصيل</strong> - يمكن لخطوط الأساس أن تقارن موانئ ومستعملي وبرمجيات صافية.<br/> <br/> <strong>البرمجيات</strong> -لمقارنة البرمجيات التي نتحقق منها لأن أرقام النسخ غير موحّدة في الشكل، عندما نتلقّى نتيجة مراجعة الحسابات، نُنشئ قاعدة جديدة تُدعى البرمجيات التي نخزنها في قاعدة البيانات، إلى جانب بقية تفاصيل البرمجيات لكل طرد. ولهذا السبب، فإن خطوط الأساس التي تستخدم سياسات البرمجيات لن تعمل عند تشغيلها ضد جهاز لم يراجع حساباته بحلول 1-10 (على الأقل). سياسات البرمجيات يمكن أن تختبر ضد النسخة "المتساوية" أو "أكثر من" أو "متساوية أو أكثر"<br/> <br/> <strong>Netstat Ports</strong> موانئ النيتستات تستخدم مزيجاً من رقم الميناء والبروتوكول والبرنامج إذا كان الجميع حاضرين فإن السياسة العامة تمر<br/> <br/> <strong>المستخدمون</strong> -المستعملون يعملون مثل ميناء (نيتست ) وفي حالة وجود مستخدم له اسم مطابق ومركز وتفاصيل كلمة السر (متغيرة، تنتهي صلاحيتها، ومطلوبة) فإن السياسة العامة تنتقل.<br/> <br/> </p>',
  'aaf63b0787b817ee82e35656da241a73af9dcb29611230495906e6c7181f88c5' => '<p>والمكونات عبارة عامة تستخدم للجداول التي تخزن الخواص للجهاز. وهذه الجداول هي: الوصول إلى النقاط، والارتفاع، والبيولوجيا، والشهادة، والخزانات، والملف، والرق، والرخصة، والسجل، والذاكرة، والوحدة، والرصد، واللوحة الأم، والشبكة، والصورة، والصفحة، والصفحة، والتجزئة، والسياسة العامة، والمتغيرات المطبوعة، والمجهز، والإذاعة، والطريق، والشعار، والخادم، والخدمة، والبرمجيات</p><p> وبالإضافة إلى ذلك، نصنف الجداول التالية أيضا على أنها ذات صلة بالجهاز: التطبيق، الملحق، المجموعة، الإبداع، الصورة.</p>',
  'c845152155bc3d06bf7399de766280f69ed61c5873f7106a1b2933ea961c376f' => '<p>وتُستخدم وثائق التفويض للوصول إلى الأجهزة.<br/> <br/>أوراق التوثيق يجب أن تكون من أول الأشياء التي تقوم بها بعد تركيبها<br/> <br/></p>',
  '71615bf639a3626d4418f552f06830adff30e7622d29b3afdb54d1fc6692bff9' => '<p>والتمكن من تحديد ما هي الآلات التي تم تشكيلها هي جزء رئيسي من إدارة النظم ومراجعة الحسابات - وسيصبح الإبلاغ عن ذلك الآن بسيطا وآلية. بمجرد أن تحدد خط الأساس الخاص بك هو تلقائيا تشغيل ضد مجموعة من الأجهزة على جدول محدد مسبقا. وسيكون ناتج خطوط الأساس هذه المنفذة متاحاً للاستطلاع على شبكة الإنترنت، أو للاستيراد إلى نظام طرف ثالث أو حتى كتقرير مطبوع.<br/> <br/> ويمكنك خطوط الأساس من الجمع بين بيانات مراجعة الحسابات ومجموعة من الخصائص التي سبق أن حددتموها (خط الأساس) لتحديد مدى امتثال الأجهزة.<br/> <br/> على سبيل المثال، قد تخلق خط أساس من جهاز تشغيل Centos 6 الذي يعمل كأحد خواديمك في مجموعة. أنت تعلم أن هذا الخادم الخاص مصمم بالطريقة التي تريدها لكنك غير متأكد إذا كانت الخواديم الأخرى في المجموعة مصممة تماماً البيسبول تمكنك من تحديد هذا<br/> <br/> </p>',
  '8332a875d5bc37bf2edda8849476136e9f21681295d88a22e6d351e0f43562cc' => '<p>الاكتشافات في قلب ما يفعله (أود)<br/> <br/>كيف لك أن تعرف "ما على شبكتي؟"<br/> <br/>الاكتشافات مُعدّة لأصناف البيانات التي تمكّنك من إدارة الاكتشافات على شبكة بضغطة واحدة، دون إدخال تفاصيل تلك الشبكة كلّ مرّة.<br/> <br/></p>',
  'f3fc8f62cbfc3371a045edecd12f7c8d5ae36958437ce6c8e8cd7ea23c1e8dec' => '<p>ويتم تشفير وثائق التفويض عند تخزينها في قاعدة البيانات.<br/> <br/>عندما يُدير جهاز للكشف، يُسترجع و يُختبَر وثائق تفويضه للتواصل أولاً (من) <code>credential</code> الجدول). If these fail, then accreditation associated with the given Org <code>credentials.org_id</code> كما يتم اختباره ضد الجهاز. وتخزن وثائق تفويض العمل على مستوى الأجهزة الفردية في طاولة الاختراع (الملاحظة - لا كلمة) باسم الجدول.<br/> <br/>SSH keys are tested before SSH username / password. وعند اختبار SSH، ستوضع أيضا علامات على وثائق التفويض بأنها تعمل بالسودو أو تكون جذورها.<br/> <br/>وتيسيراً للاستخدام، لا ينبغي أن تتضمن كلمة السر في ويندوز اقتباساً واحداً أو مزدوجاً. هذا هو الحد البعيد من أسلحة الدمار الشامل، وليس قيد مفتوح.<br/> <br/></p>',
  'a1829fc66c3154fdbd971f78dfdf5db263f5c2323ee0753e26a4b6751dbbc1f7' => '<p>وتُستخدم المجموعات كقوائم بسيطة من الأجهزة التي تتطابق مع الشروط المطلوبة. If requested using JSON they return a list of <code>devices.id</code> فقط وإذا طُلب منهم استخدام واجهة الويب، فإنهم يعيدون قائمة المعالم القياسية.<br/> <br/></p>',
  '127590d2164b5f0ea32c5acae82745fee106794176070d31dbe8c411b9464a26' => '<p>إذا كنت تنوي مراجعة آلات السحب الخاصة بك تماما، لا ننسى أنك سوف تحتاج أيضا تلك أوراق الاعتماد التي تم توفيرها في فتح الباب.</p><p>تأكّدْ بأنّك تَسْمحُ الموانئَ الصحيحةَ إذا أنت تَستعملُ Microsoft Azure (22 لSH، الخ). تحقق من الآلة الافتراضية قواعد التواصل<br/> <br/></p>',
  '7419073f514865afd999d7866160500fdb3de5bd59161d6c21dfec5945416a41' => '<p>إذا اخترت نوع من القائمة، حقل "قيم" سوف يتم تمكينه. يجب أن تضع قائمة مفصّلة من القيم القابلة للاختيار هنا هذه ستظهر في صندوق الإنزال عندما يتم تحرير الحقل<br/> <br/>مثل معظم الصفات الأخرى، يمكن تحرير الحقول بالجملة. إستخدم وظيفة (بولك إديت) كما تفعل عادة وسترى أن الحقول متاحة للمدخلات<br/> <br/>انظر إلى تفاصيل الجهاز، وفتح القسم المحتوي على الحقل و (إذا كان لديك ما يكفي من الوصول) يمكنك أن تضغط على القيمة الميدانية لتحريره.<br/> <br/></p>',
  'ce32c04b54cd31fa7a634c1a613c3548bf83b0f80783a190405c6d6ad5228b7b' => '<p>الإدمات تسمح لك باختيار الأجهزة والجداول الزمنية لفتح الباب للحديث مع النظم الخارجية<br/> <br/></p>',
  'c8c19cc15a1a8d45908f735afcd70f66e4bb8292ec3c7cb555420194d85dbc01' => '<p>الأجهزة على شبكتك يجب أن تُدار ولكن كيف تحافظ على سجلاتك حتى الآن؟ صحيفة منتشرة - لا ذلك سيكون خارج الموعد خلال ساعات إن لم يكن أياماً لماذا يدوياً يحاول الإستمرار استعملي "أوديت" للمسح التلقائي لشبكاتكم و سجلوا أجهزةكم قوائم كاملة بالبرمجيات والخدمات والأقراص والموانئ المفتوحة والمستعملين وما إلى ذلك. معرفة ما إذا كان قد أُضيفت أو أُزيلت أو غيرت.<br/> <br/>بمجرد أن تجهز (أوديت) يمكنك الجلوس و الاسترخاء على سبيل المثال ما هي الأجهزة الجديدة التي اكتشفناها هذا الأسبوع؟ ما البرمجيات الجديدة التي تم تركيبها هذا الأسبوع؟ هل كان هناك أي تغيرات في المعدات الشهر الماضي؟<br/> <br/>توسيع الحقول المخزنة بسهولة مع خصائصك الخاصة<br/> <br/>حتّى إضافة أجهزة لا صلة لها بشبكتك أو تلك الأجهزة التي لا يستطيع خادمها المفتوح الوصول إليها<br/> <br/>حاسبات، مفاتيح، دفاتر، طابعات، أو أي جهاز آخر على شبكتك<br/> <br/></p>',
  '6a588bde5807a2897b6462d2268691da6040bc7c0d7a4b6f3c0db1f0ebd45fbc' => '<p>وفي عالم الأمن الحاسوبي المتغير باستمرار، حيث يتم اكتشاف مواطن ضعف جديدة ومعالجتها كل يوم، يجب أن يكون إنفاذ الامتثال الأمني عملية مستمرة. It also needs to include a way to make adjustments to policies, as well as periodic assessment and risk monitoring. ويوفر النظام الإيكولوجي للبرنامج أدوات وسياسات قابلة للمواءمة من أجل التنفيذ السريع والفعال من حيث التكلفة والمرن لهذه العمليات.</p>',
  'fb6449601de5ae49e75810495ac14ea305758b7ab864674c7bac1775843c637e' => '<p>ويمكن للشركة المفتوحة أن تخزن المعلومات في حقول العرف المرتبطة بكل جهاز.<br/> <br/>وبمجرد إنشاء حقل إضافي يمكن استخدامه في الاستفسارات والمجموعات مثل أي عزو آخر في قاعدة البيانات.<br/> <br/></p>',
  '0cf3dbfa30f11e0891b27c8ffbf5bf4691147961c81e62dfa8aaacd1930525f6' => '<p>فتح الباب يأتي مع الكثير من الاستفسارات في البناء. إذا كنت بحاجة إلى استفسار محدد ولا شيء من الاستفسارات التي سبق أن حزمت احتياجاتك، فمن السهل جدا خلق واحد جديد وحمله في فتح-أوديت للركض.<br/> <br/></p>',
  '138be63b23a50033206557cd047a25c308a6fd15931c1221789df785f0567b2e' => '<p>فتح الباب يأتي مع العديد من الملخصات إذا كنت بحاجة إلى موجز محدد ولا أحد من الملخصات المجهزة مسبقاً يلائم احتياجاتك، فمن السهل جداً إنشاء واحد جديد وحمله في برنامج مفتوح للهرب.<br/> <br/></p>',
  '1a3cc66dd5caa24649237f1159741e48333d3f2a29fddc60148200966e05dcb1' => '<p>إذا أضفت جهازاً من نوعه، لإظهار الأيقونة المرتبطة به... ... سيكون عليك أن تنسخ يدوياً الملف المزيف إلى الدليل:<br/><em>لينكس</em>:/usr/local/open-audit/public/device images<br/><em>النوافذ</em>: c:/xampp/htdocs/open-audit/device images<br/> <br/>إذا أضفت موقعاً من نوعه، لإظهار الأيقونة المرتبطة به... ... سيكون عليك أن تنسخ يدوياً...<br/><em>لينكس</em>:/usr/local/open-audit/public/images/map icons<br/><em>النوافذ</em>: c:/xampp/htdocs/open-audit/images/map icons</p><p>عندما <i>الموارد</i> هو <code>device</code>صحيح <i>الأنواع</i> هي: <code>class</code>.. <code>environment</code>.. <code>status</code> و <code>type</code>إذا <i>الموارد</i> هو <code>locations</code> أو <code>org</code> الوحيد الصالح <i>النوع</i> هو <code>type</code>إذا <i>الموارد</i> هو <code>query</code> الوحيد الصالح <i>النوع</i> هو <code>menu_category</code>.</p>',
  'c456c88942e42dd79144d5937ba2e0bafca08c676ea0eabf70e5b94aa2e8aca9' => '<p>ويتلقى برنامج &quot; أوديت &quot; الدعم من &quot; أول وايف &quot; بمستوى مذهل من الدعم. إذا كنت تفضل مجتمع نشط من مقدمي الدعم، هناك ذلك أيضا. أين يمكنك التحدث مباشرة إلى المطورين والحصول على رد خلال 24 ساعة؟ فقط حاول ذلك مع منتجات أخرى! دعم رائع توقف بالكامل أنت بحاجة للدعم، نحن نقدم الدعم. لا عاطفة أو لكن دعم عظيم الفترة<br/> <br/></p>',
  '32f44ea3af5f8418c642b0a51ce16e725d932f7fff1dd51a2c86600a0c27b839' => '<p>ولدى نظم الحواسيب المكتبية في ميكروسوفت ويندوز قيود على الشبكات قد تؤثر على أداء نظام &quot; أوديت &quot; . The TCP/IP stack limits the number of concur incomplete outbound TCP connection attempts. وبعد بلوغ هذا الحد، تُطرح المحاولات اللاحقة للارتباط على التوالي وستُحل بمعدل ثابت (10 في الثانية). إذا دخل كثيرون جداً إلى السكة، قد يسقطون. وأخيرًا، (أباتشي) سيُعيد تشغيله بواسطة الـ(أو إس) ولهذا السبب، لا يُدعم تركيب نظام التشغيل المكتبي في ويندوز.<br/><br/>لا يوجد شيء خاطئ في قانون فتح الباب، ولا يمكننا أن نفعل أي شيء لمعالجة هذه المسألة على آلات عملاء ويندوز.</p>',
  '1cdd12db649dc901ee2b5e70c5fd0666d8cf248eed3d67cdb26ad840cd759c3a' => '<p>انظر بسرعة إلى حالة الأجهزة على شبكتك<br/> <br/></p>',
  'e1e6b54cb2652602a6a838bed90b79b977b64b49e5876a06c40f9dc461d88ce5' => '<p>(أوديت) المُفتَح يُقدّم العديد من المُتبقيات من الصندوق!<br/> <br/>والأوغاد (التنظيمات) في فتح الباب هي بند رئيسي. المستعمل لديه أورج رئيسي وقائمة بالأوغاد يمكنهم الوصول إليها المستعمل يجمع هذه مع قائمة من "الجرائم" المُعينة التي تحدد ما هي الإجراءات التي يمكن أن يتخذوها بشأن المواد المُخصصة للـ(الأوغس) التي يمكنهم الوصول إليها. مجموعة من مستعملي "أوغس" و"أحجار" تحدد ما يمكن ولا يمكن أن تفعل في "إفتتاح"<br/> <br/>وتُخصص معظم المواد في أورغ. الأجهزة والأماكن والشبكات وما إلى ذلك<br/> <br/>(أورق) يمكن أن يكون لديها طفل (أورق) فكّر في الهيكل التنظيمي (الإطار). إذا كان لدى المستعمل إمكانية الوصول إلى أوروغ محدد، لديهم أيضاً إمكانية الوصول إلى سلال الأورق.</p>',
  'cd0a86c2bf2d97fb46ad4cd82f0b19ce971af5d603ca3126b680729c39c86ba6' => '<p>(أوديت) المُفتَح يُقدّم العديد من المُتبقيات من الصندوق!<br/> <br/>والأوغاد (التنظيمات) في فتح الباب هي بند رئيسي. المستعمل لديه أورج رئيسي وقائمة بالأوغاد يمكنهم الوصول إليها المستعمل يجمع هذه مع قائمة من "الجرائم" المُعينة التي تحدد ما هي الإجراءات التي يمكن أن يتخذوها بشأن المواد المُخصصة للـ(الأوغس) التي يمكنهم الوصول إليها. مجموعة من مستعملي "أوغس" و"أحجار" تحدد ما يمكن ولا يمكن أن تفعل في "إفتتاح"<br/> <br/>وتُخصص معظم المواد في أورغ. الأجهزة والأماكن والشبكات وما إلى ذلك<br/> <br/>(أورق) يمكن أن يكون لديها طفل (أورق) فكّر في الهيكل التنظيمي (الإطار). إذا كان لدى المستعمل إمكانية الوصول إلى أوروغ محدد، لديهم أيضاً إمكانية الوصول إلى سلال الأورق. لمزيد من المعلومات، انظر هذا <a href="/index.php/faq?name=Users, Roles and Orgs">FAQ</a>.</p>',
  'e31d4ed8333c6b76dbfa8c0f41a6adb12a9df291731d577530028160d29a01bb' => '<p>ومن الأمثلة على الخصائص الصحيحة للشبكة الفرعية ما يلي: 192.168.1.1 (عنوان واحد من IP)، و 192.168.1.0/24 (a subnet)، و 192.168.1-3.1-20 (مجموعة من عناوين شركاء التنفيذ).<br/> <br/><em>ملاحظة</em> - عندما خلق <strong>بذرة</strong> ولا يمكن استخدام الاكتشافات إلا لشبكات فرعية صالحة (192.168.1.0/24). ولن تعمل راندغ (192.168.1-10-20) على تقييد شركاء التنفيذ المكتشفين. <br/> <br/><em>ملاحظة</em> - فقط شبكة فرعية (وفقا للأمثلة - 192.168.1.0/24) ستتمكن تلقائيا من إنشاء شبكة صالحة للشبكة المفتوحة. <br/> <br/>إذا كنت تستخدم نوع الدليل النشط، تأكد أن لديك وثائق تفويض مناسبة للحديث مع المراقب المالي الخاص بك <a href="../credentials">وثائق التفويض</a>.<br/> <br/></p>',
  'f4e10c00528ae733135dc7deb7ceb989e12356b67e49ff2522d62d27b4edaabb' => '<p>The <code>type</code> من الموقع سيحدد رمزه<br/> <br/></p>',
  '96c317ad0bde4dfc032daa767b6cdf35c21db65f9a9c89aa22a368ee644f219e' => '<p>والأدوار في فتح الباب هي بند رئيسي. المستعمل لديه أورج رئيسي وقائمة بالأوغاد يمكنهم الوصول إليها ويجمع المستعمل هذا مع قائمة بالأدوار المخصصة التي تحدد الإجراءات التي يمكن أن تتخذها بشأن المواد المخصصة للأوغاد التي يمكنهم الوصول إليها. مجموعة من مستعملي "أوغس" و"أحجار" تحدد ما يمكن ولا يمكن أن تفعل في "إفتتاح"<br/> <br/>إحصل على تجربة شركة (أود) المفتوحة إن إنشاء الأدوار يتيح السيطرة الدقيقة على ما يمكن لمستعمليكم القيام به في إطار نظام تبادل المعلومات المفتوح.<br/> <br/>وتستند الطريقة الرئيسية للترخيص (ما يمكن للمستعمل أن يفعله) إلى دور المستعملين. وتُعرَّف الأدوار غير المباشرة على أنها &quot; org admin &quot; ، والمراسل والمستعمل. ولكل دور مجموعة من التصاريح (الاختبار، القراءة، التحديث، حذف) لكل نقطة نهاية. وتتاح القدرة على تحديد أدوار إضافية وتحرير الأدوار القائمة في المؤسسة المفتوحة للاستثمار.<br/> <br/>ويمكن أيضاً استخدام الأدوار في أذون برنامج العمل من أجل التنمية في أفريقيا (الدليل الإيجابي والدليل المفتوح). وللمنشآت المرخصة لدى المؤسسة القدرة على تكييف مجموعة برامج العمل الطويلة الأجل لكل دور محدد.<br/> <br/></p>',
  'aafbb1e22384853d02474307395c6afbaedc5421c2b85fc08cc77c7a123a3552' => '<p>سمة المُجمعات تمكّنك من إدارة العديد من حواسيب "المُدير" التي تقوم باكتشاف الشبكة جميع المُجمعين يُسيطر عليهم مركزياً من الخادم The only required network ports between the Collector and the Server are 80 and/or 443.<br/> <br/>إنه يجعل إدارة الشبكات المتفرقة سريعة وسهلة وبسيطة مفتوح وتحصل الشركات المرخصة على رخصة جامع واحدة مشمولة بها ولديها الخيار لشراء المزيد حسب الاقتضاء.<br/> <br/></p>',
  'cc49788013179d358ad6c615f71c57e5b1eddffcab36eb7b303441bf96e0a9f5' => '<p>سمات النهاية تسمح لك بإضافة قيم مصممة خصيصاً إلى خصائص مختلفة في موقع مفتوح، في الوقت الذي تعمل فيه هذه السمة على صفات من الدرجة، والبيئة، والوضع، والنوع على النبائط، والخصائص من النوع لكل من الأماكن والأوغاد، فضلاً عن فئة منو للجرائم. إذا رأيتم صنفاً من أحد الأنواع البشعة ستلاحظون أن عزوة النوع يجب أن تختار من صندوق الإنزال هنا تخزن تلك القيم ومن ثم، إذا كنت ترغب في إضافة نوع جديد يتم اختياره من أجل موقع، إضافة ذلك باستخدام خاصية السمات.</p>',
  '738388cab3dd682c0cd1358eff8e7d968721980d15162a9c26cdacfdcb6936dd' => '<p>المهمات لها جدول زمني يعكس الجدول الزمني الموحد تُستخدم المواصفات للدقيقة، ساعة، يوم... الشهر، اليوم... يمكنك اختيار العديد من هذه باستخدام القيم المختومة (لا أماكن) يمكنك اختيار كل قيمة باستخدام<br/> <br/>The <code>type</code> ويمكن أن تكون المهمة واحدة من: خطوط الأساس، أو المجمّعين، أو الاكتشافات، أو الاستفسارات، أو التقارير، أو الملخصات.<br/> <br/>إذا كنت ترغب في جدولة خط الأساس أو الاكتشاف، سوف تحتاج إلى خلق هذه قبل إنشاء المهام. يجب أن تستخدم هويّة نوع البند في <code>sub_resource_id</code>على سبيل المثال، إذا كنت ترغب في جدولة الاكتشافات، استخدام هوية المفرزات الخاصة في <code>sub_resource_id</code>.<br/> <br/>القيمة <code>uuid</code> محدد لكل خادم مفتوح قيمتك الفريدة يمكن العثور عليها في التشكيلة<br/> <br/>The <code>options</code> والسندات هي وثيقة مشتركة تتضمن أي خصائص إضافية مطلوبة للاضطلاع بهذه المهمة. والخصائص الإضافية للتقارير والاستفسارات والملخصات هي: <code>email_address</code> و <code>format</code>(المعزوة الإضافية لـ(بسيلين <code>group_id</code>.<br/> <br/></p>',
  'b54a278a9f86c2c81b50629775866475691da0aacc1b6e345980e3bfec851341' => '<p>الجزء المؤثر من سائلك <em>يجب أن</em> تحتوي على أعمدة مؤهلة بالكامل IE - <code>SELECT devices.id AS `devices.id`, devices.name AS `devices.name` ...</code>.<br/> <br/>القسم الذي في موقعك <em>يجب أن</em> احتواء <code>WHERE @filter</code> إذاً (أوديت) المفتوح يعرف أن يقيد إستفساراتك إلى (الأوغاد) المناسبة SQL not containing this condition will result in the query failing to be created, unless you have the Admin role.<br/> <br/>كمثال على ذلك سؤال SQL يظهر خصائص على أجهزة لديها <code>os_group</code> عزو "لينكس" <br/><code>SELECT devices.id AS `devices.id`, devices.icon AS `devices.icon`, devices.type AS `devices.type`, devices.name AS `devices.name`, devices.os_name AS `devices.os_name` FROM devices WHERE @filter AND devices.os_group = "Linux"</code><br/> <br/></p>',
  '762655660249c474ff1834597320759cb4b07de73bf32ac2f75fb00ec491cc6a' => '<p>الجزء المؤثر من سائلك <em>يجب أن</em> فقط إحتواء <code>DISTINCT(devices.id)</code>.<br/> <br/>القسم الذي في موقعك <em>يجب أن</em> احتواء <code>WHERE @filter</code> إذاً (أوديت) المفتوح يعرف أن يقيد إستفساراتك إلى (الأوغاد) المناسبة غير أن شركة SQL التي لا تحتوي على هذه الحالة ستؤدي إلى عدم إنشاء المجموعة.<br/> <br/>مثال لـ SQL لاختيار جميع الأجهزة التي تدير مكتب ديبيان <code>SELECT DISTINCT(devices.id) FROM devices WHERE @filter AND devices.os_family = "Debian"</code><br/> <br/></p>',
  '1b840f868152bad2feab44fe5d9faa127f0a361031ddcf178aafeb82dbde7ec2' => '<p>The network should be in the format 192.168.1.0/24.<br/> <br/></p>',
  '91e18640acae0cfa1f8a00deae422d2a3d7255ccda313f536f0040e424bf3466' => '<p>نقطة نهاية الترخيص تسمح لك بتتبع عدد الرخص التي وجدت على أجهزةكم<br/> <br/>لخلق دخول لتعقب رخصتك <em>يجب أن</em> تقديم اسم، ومنظمة، وعدد التراخيص المكتسبة، واسم البرمجيات. في الميدان <code>match_string</code> يجب أن تُقدّم اسم البرمجيات التي تريد تعقبها، يمكنك استخدام علامة المئة (%) كبطاقة جامحة في المباراة.<br/> <br/></p>',
  '3fbd155e7c0aa813fb746c9e4142cf7313b893f5ca2606513e514c0c9c6095fb' => '<p>الأرامل يمكن أن يخلقوا بسهولة لإظهار ما هو محدد لبيئة الخاص بك على لوحات الدبابيس الخاصة بك.<br/> <br/></p>',
  '49d5ba3d5582d813940384f2f08168b397eeeb5e569ba152d753a456e8418fa6' => '<p>Vulnerabilities reporting based on the NIST CVE feed.<br/> <br/></p>',
  '9f8cd49ad14fbc25b259c8ea37e58e827f1bfd8640e3755654231ed9b4d465fe' => '<p>يمكنك أن تخلق نصاً مع كل الخيارات لأي من نصوص مراجعة الحسابات القائمة ليس فقط (ويندوز) AIX, ESX, Linux, OSX and Windows are all covered.<br/> <br/></p>',
  '3c53d806c6da1d74d6bb52aed93417a5a6d1033eb45553b03dc6033f94b0fca5' => '<p>نحن في البداية وضعنا القائمة الافتراضية للنصوص مع خيارات التقصير ولا يمكن حذف هذه النصوص الافتراضية. يمكنك أن تخلق نصوصاً إضافية لتستخدمها من قبلك السيناريو الخاص بك سيكون مستندا على واحد من النصوص الحالية ولها خيارات العرف المطبقة. يمكن بعد ذلك تحميل النصوص من صفحة القائمة في القائمة إكتشاف - مراجعة الحسابات بنود مراجعة الحسابات<br/> <br/></p>',
  '988bf640110b7b39cdf9955c92b7c850f0f27b1305eeddd253cd1fe15220ea02' => '<p>يمكنك استخدام النسبة المئوية للإشارة كبطاقة برية في المباراة<br/> <br/></p>',
  '57a4d3bfc6e01d002c5614ee63be7110b8a36434e0cad3a854a351b3144ea256' => '=',
  'c570c6e6fb130afc4c34310d50311b057562da44a83266092dd3fa8e10eddd3d' => '<p>هذه النقطة النهائية تمكنك من إضافة تفاصيل البنية التحتية السحابية بعد ذلك ستصل (أوديت) إلى سحابتك مستخدماً جهازها المحلي و يعيد خوادمك مثل أي جهاز آخر في (أوديت)<br/> <br/><em>ملاحظة</em> -لإستعمال هذه المميزة، نحن <em>يجب أن</em> (ب) تمكين أصناف التشكيلة من تطابق الـ (ماك) (بالنسبـة لـ (أزور وسيتم ذلك تلقائياً في أول مرة يتم فيها تنفيذ الاكتشاف السحابي.<br/> <br/>وثائق تفويض لسحبك<a href="/index.php/faq?name=Credentials for Microsoft Azure used in Cloud Discovery">Azure</a> أو <a href="/index.php/faq?name=Credentials for Amazon AWS used in Cloud Discovery">AWS</a>مطلوب<br/> <br/></p>',
  'f16474a9900a44186e87098f5fcb153a1fab2e401e1a6db587168b204761b276' => '♪',
  '62b67e1f685b7fef51102005dddd27774be3fee38c42965c53aab035d0b6b221' => '?',
  '92a00d7d91da9f0f06c3f218c49c9b98323469962b291365b85d3c16b6b7f95f' => '>=',
  'cf43c72aaffc258f6f1acf2c24943a4ac5921680ee5acfd16b49cd11e2e95190' => 'A CVE item that does not contain a filter to determine the affected item(s).',
  '16f431630b99e7dd84c7c20cb202cc8ad7fd90e3139edb0cf382c746c1b24882' => 'وهناك حاجة إلى مفتاح &quot; خرائط غوغل &quot; لهذه المهمة.',
  'ed609267907c8892c815b710cba45d63f85d8403d3e29d42ea26d5ccb4a1d995' => '<p>مع المحترفين والمؤسسيين المفتوحين يمكنك التأقلم والبرمجة للاكتشافات أو إعداد التقارير أو التحقق من خط الأساس برمجوا اكتشافاتكم ليتم تشغيلها ليلاً و التقارير التي سيتم إعدادها و إرسالها إلى الموظفين الرئيسيين كل صباح الجدول المعقد أو البسيط، اكتشاف الأجهزة وإعداد التقارير مجرد نقرة.<br/> <br/>(ج) وضع جداول اكتشاف فردية لكل شبكة فرعية أو متحكم في إدارة التنمية، تضاف في التقارير التي ستُنشأ للجماهير المستهدفة. وضع جداول زمنية بسيطة أو معقدة لدعم احتياجات الشركات، أو تجنب الدعم أو التأثير على العمليات، أو لمجرد نشر عملية التحميل والتسريع في مراجعة الحسابات.<br/> <br/></p>',
  'a96a26208ce187d4acffff9becc4abaa2f0365210665b9108f54e2ff27455f21' => 'A JSON صفيفة من الأجهزة IDs that will have this standard executed.',
