  '8f27af7cf869ca67a4d6801d57a83205fffafbc2ede76775b8ae6012ec55fc7d' => 'A security zone is a administrative domain or policy domain within the Network Domain.',
  'c6c69133ab2437d1fd7fc4c1b22f2aabbb9621811f3af88d69e121d7f29a45bc' => 'الاستفسار هو أساساً بيان SQL. ويتعارض هذا البيان مع قاعدة البيانات مع الإضافة التلقائية للحد الأقصى، بحيث لا ينطبق إلا على البنود المطلوبة، ولا يسمح للمستعمل إلا بالنظر في تلك البنود. يمكن إنشاء كواري باستخدام قائمة الطعام (أديروا (كويرز - (أصنعوا (كويرز - وتحتوي الاستفسارات على org-id، وبالتالي فهي تقتصر على المستعملين المناسبين. ويجب أن يكون للمستعمل دور (دور) org admin or reporter) في إنشاء أو تحديث أو حذف الاستفسار. ويمكن لجميع المستعملين أن يقدموا استفسارا. وللاستفسار اسم يُستخدم في بند القائمة وكذلك في فئة القائمة. هذا يُخبرُ جوّي مفتوحَ الذي يَضِعُ السؤالَ في. وهناك أيضا عرض قائمة الطعام التي ينبغي وضعها <i>y</i> تيسيراً للاستفسار في مذكرة التفاهم<i>n</i> لمنع ظهور الاستفسار على الإطلاق. "السؤال سيستمر لو أُطلق عليه" <code>id</code>بغض النظر عن قيمة القائمة',
  '9b6a8b18d882cc08e0cbb096338f1cb7d6fbb8f0a8b3b2cc30fcd7e449e34ea7' => 'وصف مختصر للدخول',
  '38957d79efc498509e1e9c0eea6763e3dab73fcc1fe167ed7e7b2c44d87ac2a9' => 'وصف توضيحي قصير مستعملة بالمركز و أقراص المرور',
  'f34527028629b4b51c64737410e00ad2ed4a583c88625894faefd8bde6a641af' => 'اكتشاف البذور هو نوع آخر من الاكتشافات، حيث توفر IP من واحد <i>بذرة</i> جهاز ويجري مراجعة هذا الجهاز، ثم تضاف إلى قائمة شركاء التنفيذ التي يتعين مراجعة حساباتها. ثم تُراجع هذه الأجهزة وتُضاف أيضاً إلى قائمة شركاء التنفيذ لمراجعة الحسابات. وتستمر هذه العملية بعد ذلك في حدود البارامترات التي حددها المستخدم.',
  'afe26bcec625f6ef353b9950605679af7f7319c667bb3c39df1376138ec858a6' => 'نظام منظم لإدارة المعلومات الحساسة',
