  'c4a0fdd62bdbd9d64ed0f5b94f0a33b63f6b8d756c5d69ddc219d2d6419cc4a1' => 'إذا لم تضعي عادة أجهزة مقسمة إلى (جورج) فلن يكون لها تأثير نحن فقط نتحقق من استخدام الـ(أورغايد) إذا كان قد تم اكتشافه (أو يدوياً في نص مراجعة الحسابات) ومُكنت في التشكيلة.',
  '61176fb3ce148ea374cd6b3ab1835a04aa24c0cca2b20781b09d1fa2f55ef079' => 'إذا كان لديك وثائق تفويض، يمكنك أن تتوقع كامل كمية المعلومات الممكنة.<br/><br/>ومن الواضح أن أفضل طريقة لاستخدام نظام &quot; أوديت &quot; هي الحصول على وثائق تفويض عمل للأجهزة التي يتم اكتشافها (سواء كانت شركة WMI أو SSH أو وثائق تفويض شركة SNMP).<br/><br/>ولدينا أيضا صفحة على مراجعة الحسابات بدون وثائق تفويض.',
  '0f468a2e1ec4c8a67fda6ea7f90248ac135183edb21877a0f79f0cc8b872ee0e' => 'إذا كان لديك برمجيات مضادة للفيروس تعمل، السماح لخدمات أوبمانتيك (أمكد)، وأباتشي (الشارع 2-2)، وشركة ماي إس كي إل (Msql) للبدء والركض آلياً، أمر أساسي. وتُستخدم هذه الخدمات من قِبَل شركة Open-AudIT. يجب أن تفعل هذا مرة واحدة إذا استمر برنامجك المضاد للفيروس في حثك على فتح الباب، يرجى إرسال إلى المنتديات أو إرسال البريد الإلكتروني لدعم باسم ونسخة برامجك المضادة للفيروس.',
  '883a009592aeca6692762b71804ac275047f9ed4c5edc4b3307d05d1946fc5a6' => 'إذا قمتِ عادةً بتجهيز أجهزة (موقعة من (إلى / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / / /',
